1	const PROCESSING_FEE = 5;
2	const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BASE_PREMIUM = 25;
7	const BUILDING_BLOCK_SIZE = 3;
8	const BUILDING_BLOCK_BASE_PREMIUM = 60;
9	const CURSE_SURCHARGE_RATE = 0.5;
10	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
11	const HIGH_ENCHANTMENT_THRESHOLD = 5;
12	
13	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
14	type Customer = { yearsWithMHPCO: number };
15	type QuoteStep = { op: "quote"; items: Item[] };
16	type Step = QuoteStep;
17	type Scenario = { customer: Customer; steps: Step[] };
18	
19	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const isComponent = (type: string) => COMPONENT_TYPES.has(type);
29	
30	const componentsGroupBase = (count: number): number => {
31	  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
32	  return count * COMPONENT_BASE_PREMIUM;
33	};
34	
35	const countByType = (items: Item[]): Map<string, number> =>
36	  items.reduce((counts, item) => {
37	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
38	    return counts;
39	  }, new Map<string, number>());
40	
41	const itemBasePremium = (item: Item): number => {
42	  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
43	  return MAIN_ITEM_BASE_PREMIUM[item.type];
44	};
45	
46	const itemSurcharges = (item: Item): number => {
47	  if (isComponent(item.type)) return 0;
48	  const base = itemBasePremium(item);
49	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
50	  const highEnchantment =
51	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
52	  return curse + highEnchantment;
53	};
54	
55	const policyBaseSum = (items: Item[]): number => {
56	  const mainSum = items
57	    .filter((i) => !isComponent(i.type))
58	    .reduce((sum, item) => sum + itemBasePremium(item), 0);
59	  const components = items.filter((i) => isComponent(i.type));
60	  let componentsSum = 0;
61	  for (const count of countByType(components).values()) {
62	    componentsSum += componentsGroupBase(count);
63	  }
64	  return mainSum + componentsSum;
65	};
66	
67	const policyItemSurcharges = (items: Item[]): number =>
68	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
69	
70	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
71	  const baseSum = policyBaseSum(items);
72	  const surcharges = policyItemSurcharges(items);
73	  const firstContractInsurance = baseSum * FIRST_CONTRACT_INSURANCE_RATE;
74	  const loyaltyDiscount =
75	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
76	  const followUpDiscount = isFollowUp ? baseSum * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
77	  return Math.ceil(
78	    baseSum + surcharges + firstContractInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE
79	  );
80	};
